from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            # Map common country names to nationality adjectives
            mapping = {
                "united states": "American",
                "usa": "American",
                "united states of america": "American",
                "russia": "Russian",
                "canada": "Canadian",
                "japan": "Japanese",
                "china": "Chinese",
                "france": "French",
                "germany": "German",
                "united kingdom": "British",
            }
            adj = mapping.get(low_obj, obj.strip().title())
            # Choose appropriate indefinite article
            article = "an" if adj[0].lower() in "aeiou" else "a"
            return f"was {article} {adj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Defer handling of mission/crew merging to the main loop
            return None
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    # Build a lookup from mission to its crew members for later merging
    mission_to_crew = defaultdict(list)
    for t in triples:
        if t.predicate == "crewMembers":
            mission_to_crew[t.subject].append(t.object)

    sentences = []
    for subj, items in groups.items():
        # Combine crew members into a single clause
        crew_objs = [t.object for t in items if t.predicate == "crewMembers"]
        other_items = [t for t in items if t.predicate != "crewMembers"]
        raw_descriptors = [phrase(subj, t.predicate, t.object) for t in other_items if phrase(subj, t.predicate, t.object) is not None]

        # Handle crew member merging when a subject has a mission and we have crew data for that mission
        mission_obj = None
        for t in other_items:
            if t.predicate == "mission":
                mission_obj = t.object
                break
        if mission_obj:
            # Gather all crew members for this mission, include the subject itself if not already present
            crew_list = set(mission_to_crew.get(mission_obj, []))
            crew_list.add(subj)
            crew_names = list(crew_list)
            if len(crew_names) == 1:
                crew_clause = f"{crew_names[0]} was a crew member of {mission_obj}"
            else:
                crew_names_sorted = sorted(crew_names)
                if len(crew_names_sorted) == 2:
                    crew_clause = f"{crew_names_sorted[0]} and {crew_names_sorted[1]} were crew members of {mission_obj}"
                else:
                    *first, last = crew_names_sorted
                    crew_clause = f"{', '.join(first)}, and {last} were crew members of {mission_obj}"
            raw_descriptors.append(crew_clause)
        if crew_objs:
            # Format crew list with commas and 'and'
            if len(crew_objs) == 1:
                crew_clause = f"crew members were {crew_objs[0]}"
            else:
                crew_list = ", ".join(crew_objs[:-1]) + f" and {crew_objs[-1]}"
                crew_clause = f"crew members were {crew_list}"
            raw_descriptors.append(crew_clause)
        if not raw_descriptors:
            continue

        # Separate possible nationality adjective (single word, title‑cased) from other clauses
        nationality_adj = None
        descriptors = []
        for d in raw_descriptors:
            if nationality_adj is None and d.isalpha() and d.istitle():
                nationality_adj = d
            else:
                descriptors.append(d)

        if nationality_adj:
            # Build sentence starting with the adjective
            if not descriptors:
                sent = f"The {nationality_adj} {subj}."
            elif len(descriptors) == 1:
                sent = f"The {nationality_adj} {subj} {descriptors[0]}."
            else:
                body = ", ".join(descriptors[:-1])
                sent = f"The {nationality_adj} {subj} {body}, and {descriptors[-1]}."
        else:
            if len(descriptors) == 1:
                sent = f"{subj} {descriptors[0]}."
            else:
                body = ", ".join(descriptors[:-1])
                sent = f"{subj} {body}, and {descriptors[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

